import React from 'react';
import { RallyBlog } from '../../../public/RallyBlogType';
import { BlogLink } from '../../components/BlogLinks/index';

export type PagesListProps = {
    blogs: RallyBlog[]
}

export function PagesList(props: PagesListProps) {
    const list = props.blogs.map(b =>
        <BlogLink
            key={ b[0].id }
            blog={ b }
            to={ `/blog/${ b[0].id }` }
    />);

    return (
        <div>
            { list }
        </div>
    )
}
