import * as React from 'react'; 
import classnames from 'classnames'; 
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'; 
import { IconDefinition } from '@fortawesome/free-solid-svg-icons'; 
import './icon-word.less'; 

export interface IconWordProps {
	icon: IconDefinition,
	word?: string
}

export function IconWord(props: IconWordProps) {
	const { icon, word } = props; 

	const cls = classnames('icon-container', {
		'no-margin': !word
	}); 

	return (
		<mark className={ cls }>
			<FontAwesomeIcon className="icon-font" icon={ icon } />

			{
				word ? (
					<span className="icon-word">{ word }</span>
				) : null
			}
		</mark>
	)
}
