export type SplitPosition = {
	l: boolean, 
	r: boolean
}

export type SplitResult = [JSX.Element[], SplitPosition]; 

export function numbersSplit(numbers: JSX.Element[], now: number): SplitResult {
	const position: SplitPosition = {
		l: false, 
		r: false
	}
	let show: JSX.Element[] = []; 

	if (now < 3) {
		show = numbers.slice(0, 7); 
		position.l = true; 
	} else if (now > numbers.length - 4) {
		show = numbers.slice(
			numbers.length - 7
		); 
		position.r = true; 
	} else {
		show = numbers.slice(now - 3, now + 4); 
		position.r = true; 
		position.l = true; 
	}

	return [show, position]
}
