import * as React from 'react';
import { Link } from 'react-router-dom';
import classnames from 'classnames';

import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faAngleDoubleLeft, faAngleDoubleRight } from '@fortawesome/free-solid-svg-icons';

import { numbersSplit } from './numbers-split';
import './page-choose.less';

export interface PageChooseProps {
	total: number, 
	now: number, 
	getPath?: (i: number) => string
}

export function PageChoose(props: PageChooseProps) {
	const { total, now  } = props; 

	const numbers = new Array(total).fill(0).map((_, i) => {
		const cn = classnames({
			'page-num': true, 
			'page-route': true, 
			active: i === now
		}); 

		const to = props.getPath ? 
			props.getPath(i) : `/pages/${i}`

		return (
			<Link className={ cn } key={ i } to={ to }>{ i }</Link>
		);
	}); 

	const [show, position] = numbersSplit(numbers, now); 

	const { l, r } = position; 

	return (
		<div className="page-choose">
			{
				r ? (
					<Link className="page-num page-route" to={
						props.getPath ? 
							props.getPath(0) : 
							`/pages/0`
					}>
						<FontAwesomeIcon icon={ faAngleDoubleLeft } />
					</Link>
				) : null
			}
			{ show }
			{
				l ? (
					<Link className="page-num page-route" to={
						props.getPath ? 
							props.getPath(numbers.length - 1) : 
							`/pages/${numbers.length - 1}`
					}>
						<FontAwesomeIcon icon={ faAngleDoubleRight } />
					</Link>
				) : null
			}
		</div>
	); 
}