import * as React from 'react'; 
import { Link, LinkProps } from 'react-router-dom';
import { RallyBlog } from '../../../public/RallyBlogType';
import { IconWord } from '../IconWord';
import { /*faAsterisk,*/ faClock, faTag, faCode } from '@fortawesome/free-solid-svg-icons'; 

import * as U from '../../../public/utils'; 

export interface BlogLinksProps {
	blogs: RallyBlog<Date>[]
}

import './blog-links.less'; 

export type BlogLinkProps = {
	blog: RallyBlog<Date>,
	to: string
}

export function BlogLink(props: BlogLinkProps) {
	const [meta] = props.blog;

	return (
		<div className="blog-link" key={ meta.id }>
			<GotoBlog blogId={ meta.id } className="page-route">
				<p className="blog-link-title">{ meta.title }</p>

				<IconWord icon={ faClock } word={ U.date2yymmdd(meta.time) } />
				
				{  // Tags 
					meta.tags &&
					meta.tags.map(
						tag => <IconWord icon={ faTag } word={ tag } key={ tag } />
					)
				}
			</GotoBlog>
		</div>
	);
}

export interface GotoBlogProps extends React.PropsWithChildren<Partial<LinkProps<any>>> {
	blogId: string;
	className?: string;
}

export function GotoBlog(props: GotoBlogProps) {
	const { blogId, children } = props;

	const over = {
		...props
	}
	delete over.blogId;

	const to = blogId.startsWith('/') ? blogId : `/blog/${ blogId }`;

	return (
		<Link { ...over } to={ to }>
			{ children }
		</Link>
	)
}
