import React from 'react';
import { RouteComponentProps } from 'react-router-dom';
import { store } from '../../store/index';
import { RallyBlog } from '../../../public/RallyBlogType';
import { DefaultLoading } from '../../components/Loading/index';
import { faClock, faTag } from '@fortawesome/free-solid-svg-icons';
import { IconWord } from '../../components/IconWord/index';
import * as U from '../../../public/utils';

import './blog.less';
import { NetMsgBlogData } from '../../NetMsgData';
import { BlogFooter } from '../../components/BlogFooter';

import { Back2Top } from '../../components/Back2Top';
import { RArticle } from '../../components/RArticle';

export type BlogPageParams = {
    id: string
}

const getBlogApiUrl = (id: string) => `/api/blog/${id}`;

export function BlogPage(props: RouteComponentProps<BlogPageParams>) {
    const { id } = props.match.params;
    const url = getBlogApiUrl(id);

    console.log('BLOGPAGE INIT', props.match.params);

    const [
        [pagesData, setPagesData], 
        whenMountedLoading
    ] = store.createHooks<NetMsgBlogData>(url, err => {

    });

    React.useEffect(whenMountedLoading, [props]);

    if (pagesData) {
        const { blog, footer, nowIdx } = pagesData.data;
        // && !pagesData.pendding && pagesData.data
        return (
            <div className="blog-route-container">
                <BlogPageHeader blog={ blog } />
                <RArticle blog={ blog } />

                <hr className="footer-hr" />
                <hr className="footer-hr" />
                <BlogFooter nowIdx={ nowIdx } now={ blog } prev={ footer.prev } next={ footer.next } />
                <hr className="footer-hr" />
                <hr className="footer-hr" />

                <Back2Top />
            </div>
        );
    } else {
        return (
            <DefaultLoading />
        )
    }
}

export function BlogPageHeader(props: { blog: RallyBlog }) {
    const { blog } = props;
    const [ meta ] = blog;

    return (
        <header className="blog-info">
            <section className="icons">
                <time>
                    <IconWord icon={ faClock } word={ U.date2yymmdd(meta.time) } />
                </time>
                
                {  // Tags 
                    meta.tags.map(
                        tag => <IconWord icon={ faTag } word={ tag } key={ tag } />
                    )
                }
            </section>
            <section className="title">{ meta.title }</section>
        </header>
    )
}
