import React from 'react';
import { RallyBlog, RallyNode, TagNode } from '../../RallyBlogType';

import './rally-article.less';

export interface RArticleProps {
    blog: RallyBlog
}


function CodePreviewWindow(props: { node: TagNode, blogId: string }) {
    const { node, blogId } = props;

    const [opened, setOpened] = React.useState(false);

    const filename = node.attribs.filename;

    const previewLink = `/code-preview/${ blogId }-${ filename }`;

    return <>
        { 
            filename ?
                <a style={{ display: 'hidden' }}
                    className="page-route"
                    href={ previewLink } about="预览链接，默认隐藏" /> :
                null
        }
        <pre { ...node.attribs }>
            { ...renderTag(node.children, blogId) }
        </pre>
        {
            filename ? (
                <div className="code-preview">
                    {
                        opened ? (
                            <div className="_preview">
                                <iframe className="_iframe page-route" src={ previewLink } />
                            </div>
                        ) : null
                    }
                    <div className="_toggle clickable" onClick={ () => setOpened(!opened) }>
                        { opened ? 'Close' : 'Run !' }
                    </div>
                </div>
            ) : null
        }
    </>
}

function renderTag(nodes: RallyNode[], blogId: string): React.ReactNode[] {

    return nodes.map((node, idx) => {
        if (node.type === 'comment') return null;

        if (node.type === 'style' || node.type === 'script') {
            const child = node.children[0];
            return React.createElement(node.type, {
                ...node.attribs,
                key: idx
            }, child ? child.data : null);
        }

        if (node.type === 'text') {
            // return node.data.replace(/\&lt;/g, '<').replace();
            return <span key={ idx } dangerouslySetInnerHTML={{ __html: node.data }} />
        }

        if (node.name === 'pre') {
            return <CodePreviewWindow key={ idx } node={ node } blogId={ blogId } />
        }

        return React.createElement(
            node.name,
            { ...node.attribs, key: idx },
            ...renderTag(node.children, blogId)
        );
    });
}

export function RArticle(props: RArticleProps) {
    const { blog } = props;
    const [metaInfo, rallyNodes] = blog;
    
    console.log('!', rallyNodes)
    const lists = renderTag(rallyNodes, metaInfo.id)
    console.log('!!!!!')

    return (
        <article className="content">
            { lists }
        </article>
    )
}
