import React from 'react';
import { EventEmitter } from 'eventemitter3';
import { NetMsg, NetError, NetErrorHandler } from '../../public/NetMsg';

export type StoreData<T> = {
    pendding: boolean;
    error: NetError | null;
    data: T,
}

export type StoreMap = {
    [key: string]: StoreData<any>
}

export class Store {
    bus = new EventEmitter();

    map: StoreMap = {};

    setMapData(key: string, data: any, pendding: boolean = false) {
        this.map[key] = {
            pendding, data, error: null
        };
    }

    removeKey(key: string) {
        delete this.map[key];
    }

    isAllLoaded() {
        return Object.keys(this.map).every(k => {
            return this.map[k].pendding;
        });
    }

    clearMap() {
        const preMap = this.map;
        this.map = {};
        return preMap;
    }

    getData<T = any>(key: string): StoreData<T> | null {
        return this.map[key] || null;
    }
    
    load<T = any>(str?: string): [ string, Promise<StoreData< T >> ] {
        const url = str ? str : (`/api` + location.pathname);
        
        this.map[url] = {
            pendding: true, data: null, error: null
        }

        return [
            url, 
            fetch(url).then(d => {
                if (d.status === 200) {
                    return d.json();
                } else {
                    const error = new NetError(d.status, 'Caused By Network');
                    this.bus.emit('update error', error);

                    this.map[url].error = error;
                    throw error;
                }
            }).then((resp: NetMsg<any>) => {
                if (resp.code === 200) {
                    this.map[url].data = resp.data;
                    this.map[url].pendding = false;
                    this.bus.emit('updated', url);
                    return this.map[url];
                } else {
                    throw new NetError(resp.code, 'Caused By Server');
                }
            })
        ];
    }

    createHooks<T>(key: string, errHandler: NetErrorHandler): [
        [StoreData<T> | null, React.Dispatch<React.SetStateAction<StoreData<T> | null>>],
        () => () => any
    ] {       
        const [pagesData, setPagesData] = React.useState(
            this.getData<T>(key)
        );

        return [
            [pagesData, setPagesData],

            () => {
                console.log('Pages Mounted', pagesData);

                if (this.map.INITED) {
                    delete this.map.INITED;
                    console.log(`map inited from ssr __INIT_STORE_MAP__`);
                } else {
                    // 刷新
                    setPagesData(null);
                    const [KEY, loading] = this.load<T>(key);
                    loading.then(newPagesData => {
                        // ok 
                        console.log('Finish newPagesData', KEY, newPagesData, pagesData);
                        setPagesData(newPagesData);
                    }).catch((err: NetError) => {
                        console.error('PagesPageError', err);
                        errHandler(err);
                    });
                }

                return () => this.removeKey(key);
            }
        ]
    }

    staticLoad(key: string) {
        // console.log('Static Store Hooks:', key);
        const [, loading] = this.load<any>(key);

        return loading.then(newPagesData => {
            // console.log('Finish newPagesData:', key);
            return newPagesData;
        }).catch((err: NetError) => {
            if (err.status === 404) {
                console.log('API 404:', key, 'IGNORED');
                this.removeKey(key);
            } else {
                throw err;
            }
        });
    }
}

export const store = new Store();

// @ts-ignore
if (this.document) {
    // @ts-ignore
    window.store = store;
}
