import React from 'react';
import svg from './onloading.svg';
import './loading.less'; 

export function DefaultLoading() {
	return (
		<div className="loading-pendding" style={{
			width: '2em', height: '2em', margin: '0 auto' }}>
			<img src={ svg } />	
		</div>
	);
}

export type LoadingProps = React.PropsWithChildren<{
	loading: boolean,
	component?: any,
}>

export function Loading(props: LoadingProps) {
	const { component, children, loading } = props;
	const onload = component || <DefaultLoading />;

	return loading ? 
		onload : 
		children
}
