import { RallyBlog } from './RallyBlogType';

export function prefix(str: string, length = 2, fill = '0') {
	return (fill.repeat(2) + str.toString()).slice(-length);
}

export function date2yymmdd(d: Date | string, split: string = '-') {
	if (typeof d === 'string') {
		d = new Date(d);
	}

	const year = d.getFullYear(); 
	const month = d.getMonth() + 1; 
	const date = d.getDate(); 

	return [
		year,
		prefix(month.toString()),
		prefix(date.toString())
	].join(split); 
}

export const K = 1.2; 
export function back2top() {
	const nowTop = window.scrollY; 
	const nowLeft = window.scrollX; 

	const nextTop = nowTop / K; 

	if (nextTop <= 1) {
		window.scrollTo(nowLeft, 0); 
	} else {
		window.scrollTo(nowLeft, nextTop); 
		window.requestAnimationFrame(back2top); 
	}
}

// Blog 数据的数据瘦身
export function blogSlimer<T = Date>(blog: RallyBlog<T>): RallyBlog<T> {
	const [meta] = blog;
	return [meta, [], '*'];
}
