import React from 'react';
import { RallyBlog } from "../../RallyBlogType";


import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';

import { faCaretLeft, faCaretRight } from '@fortawesome/free-solid-svg-icons';
import './blog-footer.less';
import { GotoBlog } from '../BlogLinks';

export interface BlogFooterProps {
    prev: RallyBlog | null,
    now: RallyBlog,
    nowIdx: number,
    next: RallyBlog | null
}

export function BlogFooter(props: BlogFooterProps) {
    const { prev, next, now, nowIdx } = props;
    const [nowMeta] = now;

    return (
        <div className="blog-footer-main">
            {
                <GotoBlog blogId={ prev ? prev[0].id : '/pages/0' } className="_prev">
                    <span className="_icon"><FontAwesomeIcon icon={ faCaretLeft } /></span>
                    <span>{ prev ? prev[0].title : '回到列表' }</span>
                </GotoBlog>
            }

            <div className="_current">
                <span className="_smaller _grey">第</span>
                <span className="_nums _grey">{nowIdx + 1}</span>
                <span className="_smaller _grey">篇</span>
                
                <div className="_now-id">
                    { nowMeta.title }
                </div>
            </div>

            {
                <GotoBlog blogId={ next ? next[0].id : '/pages/0' } className="_next">
                    <span>{ next ? next[0].title : '回到列表' }</span>
                    <span className="_icon"><FontAwesomeIcon icon={ faCaretRight } /></span>
                </GotoBlog>
            }
        </div>
    )
}