import React from 'react'; 
import EventEmitter from 'eventemitter3';
import './code-preview.less';
import { RouteComponentProps } from 'react-router-dom';

export const $bus = new EventEmitter<{
    log: any[][]
}>();

export interface CodePreviewProps {
    url: string
}

const originLog = console.log;

console.log = (...args: any[]) => {
    $bus.emit('log', args);
    originLog(...args);
}


function PrintLine(props: { line: unknown[] }) {
    const { line } = props;

    const str = line.map(sub => {
        if (typeof sub === 'object') return JSON.stringify(sub, (k, v) => v, '  ')
        if (typeof sub === 'number') return sub.toString();
        if (typeof sub === 'bigint') return sub.toString();
        if (typeof sub === 'function') return `[function ${ sub.name }]`
        if (typeof sub === 'boolean') return sub.toString();
        if (typeof sub === 'symbol') return sub.toString();
        if (typeof sub === 'undefined') return 'undefined';
        if (typeof sub === 'string') return sub;
        return '[ERR_UNKDOWN_TYPE]'
    }).join(' ')

    return (
        <code>{ str }</code>
    )
}

export function CodePreview(props: CodePreviewProps) {
    
    const { url } = props;

    const [lines, setLines] = React.useState<unknown[][]>([]);
    const [showConsole, setShowConsole] = React.useState(true);

    React.useEffect(() => {
        const $s = document.createElement('script');
        $s.src = url;
        document.body.append($s);
        
        return () => {
            $s.remove();
            setLines([]);
        }
    }, []);

    React.useEffect(() => {
        let QUEUE: any[] = [];
        let TIMER: any;

        $bus.on('log', (line: unknown) => {
            // const line = args;
            QUEUE.push(line);

            clearTimeout(TIMER);
            TIMER = null;
            TIMER = setTimeout(() => {
                setLines(lines.concat(QUEUE))
                QUEUE = [];
            }, 0);
            // setLines(lines.concat(line))
        });

        return () => {
            $bus.removeAllListeners('log')
        }
    }, [lines]);

    return (
        <div className="code-preview">
            <div className="_page">
                <div id="demo"></div>
                <div id="demo2"></div>
            </div>
            
            <pre className="_console">
                <div className="_btns">
                    {
                        showConsole ? 
                            <div className="_btn" onClick={ () => setShowConsole(false) }>隐藏</div> :
                            <div className="_btn" onClick={ () => setShowConsole(true ) }>显示输出流</div>
                    }
                    {/* <div className="_btn _disable">console.log 控制流</div> */}
                </div>
                {
                    showConsole ? (
                        <div className="_lines">{
                            lines.map((l, idx) => {
                                const dl = ('00' + (idx + 1).toString()).slice(-2);
                                return (
                                    <pre className="_line" data-line={ dl } key={ idx }>
                                        <PrintLine line={ l } />
                                    </pre>
                                )
                            })
                        }</div>
                    ) : null
                }
            </pre>
        </div>
    )
}
