import React from 'react';
import { store } from '../../store/index';
import { RouteComponentProps } from 'react-router-dom';
// import { NetError } from '../../../public/NetMsg';
import { NetMsgPagesData } from '../../../public/NetMsgData';
import { PagesList } from './PagesList';
import { PageChoose } from '../../components/PageChoose/index';
import { Loading, DefaultLoading } from '../../components/Loading/index';

export type PagesParams = {
    nth: string;
}

function getPageApiUrl(nth: string | number) {
    return `/api/pages/${nth}`;
}
export function PagesPage(props: RouteComponentProps<PagesParams>) {
    const { nth } = props.match.params;
    const url = getPageApiUrl(nth);

    const [
        [pagesData, setPagesData],
        whenMountedLoading
    ] = store.createHooks<NetMsgPagesData>(url, err => {
        console.error('Error When Loading Data From Store');
    });

    React.useEffect(whenMountedLoading, [ props ]);

    if (pagesData) {
        // && !pagesData.pendding && pagesData.data

        return (
            
            <div>
                <PagesList blogs={ pagesData.data.blogs } />
                <PageChoose total={ pagesData.data.totalPage } now={ +nth } />
            </div>
            
        );
    } else {
        return (
            <DefaultLoading />
        )
    }
}
