export type NetMsg<T = any> = {
    code: number,
    data: T,
    msg?: string
}

export type NetErrorHandler = (err: NetError) => any;

export function createNetMsg<T>(code: number, data: T, msg?: string): NetMsg<T> {
    return { code, data, msg }
}

export class NetError extends Error {
    constructor(
        readonly status: number,
        readonly msg?: string
    ) {
        super('NET_ERROR');
    }
}
